package com.qinet.feastique.service.consumablesimport com.qinet.feastique.common.mapper.toResponseimport com.qinet.feastique.exception.DuplicateFoundExceptionimport com.qinet.feastique.exception.PermissionDeniedExceptionimport com.qinet.feastique.exception.RequestedEntityNotFoundExceptionimport com.qinet.feastique.exception.UserNotFoundExceptionimport com.qinet.feastique.model.dto.FoodAvailabilityDtoimport com.qinet.feastique.model.dto.consumables.FoodDtoimport com.qinet.feastique.model.entity.Menuimport com.qinet.feastique.model.entity.consumables.addOn.AddOnimport com.qinet.feastique.model.entity.consumables.addOn.FoodAddOnimport com.qinet.feastique.model.entity.consumables.complement.Complementimport com.qinet.feastique.model.entity.consumables.complement.FoodComplementimport com.qinet.feastique.model.entity.consumables.food.Foodimport com.qinet.feastique.model.entity.discount.Discountimport com.qinet.feastique.model.entity.discount.FoodDiscountimport com.qinet.feastique.model.entity.image.FoodImageimport com.qinet.feastique.model.entity.size.FoodSizeimport com.qinet.feastique.model.entity.user.Vendorimport com.qinet.feastique.model.enums.*import com.qinet.feastique.repository.menu.MenuRepositoryimport com.qinet.feastique.repository.consumables.addOn.AddOnRepositoryimport com.qinet.feastique.repository.consumables.complement.ComplementRepositoryimport com.qinet.feastique.repository.consumables.food.FoodRepositoryimport com.qinet.feastique.repository.discount.DiscountRepositoryimport com.qinet.feastique.repository.user.VendorRepositoryimport com.qinet.feastique.response.consumables.food.FoodResponseimport com.qinet.feastique.response.pagination.WindowResponseimport com.qinet.feastique.security.UserSecurityimport com.qinet.feastique.utility.CursorEncoderimport com.qinet.feastique.utility.DuplicateUtilityimport com.qinet.feastique.utility.SecurityUtilityimport org.slf4j.LoggerFactoryimport org.springframework.data.domain.*import org.springframework.stereotype.Serviceimport org.springframework.transaction.annotation.Transactionalimport java.util.*import kotlin.jvm.optionals.getOrElse@Serviceclass FoodService(    private val foodRepository: FoodRepository,    private val vendorRepository: VendorRepository,    private val menuRepository: MenuRepository,    private val duplicateUtility: DuplicateUtility,    private val discountRepository: DiscountRepository,    private val complementRepository: ComplementRepository,    private val addOnRepository: AddOnRepository,    private val securityUtility: SecurityUtility,    private val cursorEncoder: CursorEncoder) {    private val logger = LoggerFactory.getLogger(javaClass)    @Transactional(readOnly = true)    fun getFoodById(id: UUID, vendorDetails: UserSecurity): Food {        val role = securityUtility.getRole(vendorDetails)        return foodRepository.findById(id)            .orElseThrow { RequestedEntityNotFoundException("No food found for id: $id") }            .also {                if (role == "VENDOR" && it.vendor.id != vendorDetails.id) {                    throw PermissionDeniedException("You do not have permission to access discount.")                }            }    }    @Transactional(readOnly = true)    fun getAllFoods(vendorDetails: UserSecurity, page: Int, size: Int): Page<FoodResponse> {        val pageable = PageRequest.of(page, size, Sort.by("name").ascending())        return foodRepository.findAllByVendorId(vendorDetails.id, pageable).map { it.toResponse() }    }    @Transactional(readOnly = true)    fun scrollFoods(        vendorId: UUID,        cursor: String?,        size: Int = Constants.DEFAULT_PAGE_SIZE.type    ): WindowResponse<FoodResponse> {        val currentOffset = cursor?.toLongOrNull() ?: 0L        val scrollPosition = if (currentOffset == 0L) ScrollPosition.offset() else ScrollPosition.offset(currentOffset)        val sort = Sort.by("name").ascending()        val window = foodRepository.findAllByVendorId(vendorId, scrollPosition, sort, Limit.of(size)).map { it.toResponse() }        return window.toResponse(currentOffset) { cursorEncoder.encodeOffset(it) }    }    @Transactional    fun deleteFood(id: UUID, vendorDetails: UserSecurity) {        foodRepository.delete(getFoodById(id, vendorDetails))    }    @Transactional    fun saveFood(food: Food): Food {        return foodRepository.saveAndFlush(food)    }    @Transactional    fun changeFoodAvailability(foodAvailabilityDto: FoodAvailabilityDto, id: UUID, vendorDetails: UserSecurity): Food {        val food = getFoodById(id, vendorDetails)        if (food.availability != Availability.fromString(foodAvailabilityDto.availability)) {            food.availability = Availability.fromString(foodAvailabilityDto.availability)        }        foodAvailabilityDto.addOns?.let { changeAddOnAvailability(foodAvailabilityDto, food) }        foodAvailabilityDto.complements?.let { changeComplementAvailability(foodAvailabilityDto, food) }        foodAvailabilityDto.foodSizes?.let { changeFoodSizeAvailability(foodAvailabilityDto, food) }        val updatedFood = saveFood(food)        logger.info("Food '{}' availability toggled to '{}' by vendor '{}'", id, updatedFood.availability!!.type, vendorDetails.id)        return updatedFood    }    /**     * Creates or updates a food item for the authenticated vendor.     *     * - Create: when [foodDto].id is null — generates a sequential food number and checks for duplicate names.     * - Update: when [foodDto].id is provided — ownership is verified; duplicate check runs only if the name changed.     *     * Nested collections (sizes, complements, addOns, images, orderTypes, discounts) are reconciled:     * existing children are reused or updated, and children absent from the DTO are removed.     * Returns the food reloaded with all relationships eagerly fetched.     *     * @throws UserNotFoundException when the vendor cannot be found     * @throws RequestedEntityNotFoundException when updating a non-existent food id     * @throws PermissionDeniedException when the food belongs to another vendor     * @throws DuplicateFoundException when the name already exists for this vendor     * @throws IllegalArgumentException when required fields are missing or invalid     */    @Transactional    fun addOrUpdateFood(foodDto: FoodDto, vendorDetails: UserSecurity): Food {        val vendor = vendorRepository.findById(vendorDetails.id)            .orElseThrow { UserNotFoundException("Vendor not found.") }        val food: Food = if (foodDto.id != null) {            getFoodById(foodDto.id!!, vendorDetails)        } else {            Food().apply { this.vendor = vendor }        }        val foodName = requireNotNull(foodDto.foodName) { "Please enter a food name." }        val mainCourse = requireNotNull(foodDto.mainCourse) { "Please enter a main course." }        val description = requireNotNull(foodDto.description) { "Please enter a description." }        val basePrice = requireNotNull(foodDto.basePrice) { "Please enter a base price." }        val preparationTime = requireNotNull(foodDto.preparationTime) { "Please enter a preparation time." }        val deliverable = requireNotNull(foodDto.deliverable) { "Please specify if food is deliverable." }        val dailyDeliveryQuantity = foodDto.dailyDeliveryQuantity        val deliveryTime = foodDto.deliveryTime        val deliveryFee = foodDto.deliveryFee        val availability = Availability.fromString(foodDto.availability)        val readyAsFrom = foodDto.readyAsFrom ?: vendor.openingTime        val quickDelivery = foodDto.quickDelivery        if (foodDto.id == null) {            if (duplicateUtility.isDuplicateFoodFound(foodName, vendorDetails.id)) {                throw DuplicateFoundException("A food with the name: ${foodDto.foodName} already exist. Cannot add duplicate.")            }            food.name = foodName            val lastFood = foodRepository.findTopOrderByFoodNumberDescWithLock().firstOrNull()            val nextNumber = lastFood?.foodNumber?.takeLast(5)?.toInt()?.plus(1) ?: 1            food.foodNumber = "FD-%05d".format(nextNumber)        } else {            if (food.name != foodName) {                if (duplicateUtility.isDuplicateFoodFound(foodName, vendorDetails.id)) {                    throw DuplicateFoundException("A food with the name: ${foodDto.foodName} already exist. Cannot add duplicate.")                }                food.name = foodName            }        }        food.apply {            this.mainCourse = mainCourse            this.description = description            this.basePrice = basePrice            this.preparationTime = preparationTime            this.deliverable  = deliverable            this.dailyDeliveryQuantity = dailyDeliveryQuantity            this.deliveryTime = deliveryTime            this.deliveryFee = deliveryFee            this.availability = availability            this.readyAsFrom = readyAsFrom            this.quickDelivery = quickDelivery        }        val managedFood = saveFood(food)        foodDto.addOns?.let { prepareFoodAddOns(foodDto, managedFood, vendor) } ?: food.foodDiscounts.clear()        managedFood.availableDays = prepareFoodAvailableDays(foodDto, managedFood)        managedFood.foodComplements = prepareFoodComplements(foodDto, managedFood, vendor)        foodDto.discounts?.let { prepareFoodDiscounts(foodDto, managedFood, vendor) } ?: managedFood.foodDiscounts.clear()        managedFood.foodImages = prepareFoodImages(foodDto, managedFood)        managedFood.orderTypes = prepareFoodOrderTypes(foodDto, managedFood)        managedFood.foodSizes = prepareFoodSizes(foodDto, managedFood)        menuRepository.save(prepareMenu(foodDto, managedFood))        saveFood(managedFood)        return foodRepository.findByIdWithAllRelations(managedFood.id)            .orElseThrow { RequestedEntityNotFoundException("Food not found.") }    }    private fun prepareMenu(foodDto: FoodDto, food: Food): Menu {        val menu = if (foodDto.id != null) {            menuRepository.findById(food.menu.id)                .getOrElse { throw RequestedEntityNotFoundException("Menu item not found.") }        } else {            Menu().apply {                this.food = food                deliveryItemsLeft = food.dailyDeliveryQuantity // null -> unlimited, 0 -> sold out            }        }        food.orderTypes.forEach { orderType ->            when (orderType) {                // null -> sold out, false -> not offered, true -> available                // DELIVERY: true + deliveryItemsLeft = null -> unlimited, > 0 -> available, = 0 -> sold out                OrderType.DELIVERY -> menu.delivery = true                OrderType.DINE_IN  -> menu.dineIn   = true                OrderType.PICKUP   -> menu.pickup   = true                else -> throw IllegalArgumentException("Unknown order type selected.")            }        }        return menu    }    private fun prepareFoodAddOns(foodDto: FoodDto, food: Food, vendor: Vendor) {        val existingFoodAddOns = food.foodAddOns.associateBy { it.addOn.id }        val updatedFoodAddOns = foodDto.addOns!!.map { dto ->            var addOn = AddOn().apply {                dto.id?.let { this.id = it }                this.vendor = vendor                this.name = requireNotNull(dto.addOnName)                this.price = requireNotNull(dto.price)                this.availability = requireNotNull(Availability.fromString(dto.availability!!))            }            addOn = addOnRepository.saveAndFlush(addOn)            val foodAddOn = dto.id?.let { existingFoodAddOns[it] } ?: FoodAddOn().apply { this.food = food }            foodAddOn.addOn = addOn            foodAddOn        }        food.foodAddOns.removeIf { existing -> updatedFoodAddOns.none { it.addOn.id == existing.addOn.id } }        updatedFoodAddOns.forEach { updated ->            if (food.foodAddOns.none { it.addOn.id == updated.addOn.id }) food.foodAddOns.add(updated)        }    }    private fun prepareFoodComplements(foodDto: FoodDto, food: Food, vendor: Vendor): MutableSet<FoodComplement> {        if (foodDto.complements.isEmpty()) throw IllegalArgumentException("A food must have at least one complement.")        val existingFoodComplements = food.foodComplements.associateBy { it.complement.id }        val updatedFoodComplements = foodDto.complements.map { dto ->            var complement = Complement().apply {                dto.id?.let { this.id = it }                this.vendor = vendor                this.name = requireNotNull(dto.complementName)                this.price = requireNotNull(dto.price)                this.availability = Availability.fromString(dto.availability)            }            complement = complementRepository.saveAndFlush(complement)            val foodComplement = dto.id?.let { existingFoodComplements[it] } ?: FoodComplement().apply { this.food = food }            foodComplement.complement = complement            foodComplement        }        food.foodComplements.removeIf { existing -> updatedFoodComplements.none { it.complement.id == existing.complement.id } }        updatedFoodComplements.forEach { updated ->            if (food.foodComplements.none { it.complement.id == updated.complement.id }) food.foodComplements.add(updated)        }        return food.foodComplements    }    private fun prepareFoodDiscounts(foodDto: FoodDto, food: Food, vendor: Vendor) {        val existingFoodDiscounts = food.foodDiscounts.associateBy { it.discount.id }        val updatedFoodDiscounts = foodDto.discounts!!.map { dto ->            var discount = dto.id?.let { id ->                discountRepository.findById(id)                    .orElseThrow { RequestedEntityNotFoundException("Discount with id $id not found") }            } ?: Discount().apply { this.vendor = vendor }            discount.apply {                discountName = requireNotNull(dto.discountName)                percentage = requireNotNull(dto.percentage)                startDate = requireNotNull(dto.startDate)                endDate = requireNotNull(dto.endDate)            }            discount = discountRepository.save(discount)            val foodDiscount = dto.id?.let { existingFoodDiscounts[it] } ?: FoodDiscount().apply { this.food = food }            foodDiscount.discount = discount            foodDiscount        }        food.foodDiscounts.removeIf { existing -> updatedFoodDiscounts.none { it.discount.id == existing.id } }        updatedFoodDiscounts.forEach { updated ->            if (food.foodDiscounts.none { it.discount.id == updated.discount.id }) food.foodDiscounts.add(updated)        }    }    private fun prepareFoodSizes(foodDto: FoodDto, food: Food): MutableSet<FoodSize> {        if (foodDto.foodSizes.isEmpty()) throw IllegalArgumentException("Please select at least one food size.")        val existingFoodSizes = food.foodSizes.associateBy { it.id }        val updatedFoodSizes = foodDto.foodSizes.map { dto ->            val foodSize = existingFoodSizes[dto.id] ?: FoodSize().apply { this.food = food }            foodSize.apply {                this.size = Size.fromString(requireNotNull(dto.size))                name = dto.sizeName ?: this.size!!.name                priceIncrease = dto.priceIncrease                availability = requireNotNull(Availability.fromString(dto.availability!!))            }        }        food.foodSizes.removeIf { existing -> updatedFoodSizes.none { it.id == existing.id } }        updatedFoodSizes.forEach { updated ->            if (food.foodSizes.none { it.id == updated.id }) food.foodSizes.add(updated)        }        return food.foodSizes    }    private fun prepareFoodAvailableDays(foodDto: FoodDto, food: Food): MutableSet<Day> {        val existingAvailableDays = food.availableDays        val incomingAvailableDays = if (foodDto.availableDays.isEmpty()) {            throw IllegalArgumentException("At least one day must be selected.")        } else {            foodDto.availableDays.map { Day.fromString(it) }.toSet()        }        existingAvailableDays.removeIf { it !in incomingAvailableDays }        incomingAvailableDays.forEach { if (it !in existingAvailableDays) existingAvailableDays.add(it) }        return existingAvailableDays    }    private fun prepareFoodOrderTypes(foodDto: FoodDto, food: Food): MutableSet<OrderType> {        val existingOrderTypes = food.orderTypes        val incomingOrderTypes = if (foodDto.orderTypes.isEmpty()) {            throw IllegalArgumentException("At least one order type must be selected.")        } else {            foodDto.orderTypes.map { OrderType.fromString(it) }.toSet()        }        existingOrderTypes.removeIf { it !in incomingOrderTypes }        incomingOrderTypes.forEach { if (it !in existingOrderTypes) existingOrderTypes.add(it) }        return existingOrderTypes    }    private fun prepareFoodImages(foodDto: FoodDto, food: Food): MutableSet<FoodImage> {        if (foodDto.foodImages.isEmpty() || foodDto.foodImages.size < 2) {            throw IllegalArgumentException("Please add at least 2 images of the food")        }        val existingFoodImages = food.foodImages.associateBy { it.id }        val updatedImages = foodDto.foodImages.map { dto ->            val image = existingFoodImages[dto.id] ?: FoodImage().apply { this.food = food }            image.imageUrl = dto.imageUrl            image        }        food.foodImages.removeIf { existing -> updatedImages.none { it.id == existing.id } }        updatedImages.forEach { updated ->            if (food.foodImages.none { it.id == updated.id }) food.foodImages.add(updated)        }        return food.foodImages    }    private fun changeAddOnAvailability(foodAvailabilityDto: FoodAvailabilityDto, food: Food) {        val addOnsToToggle = foodAvailabilityDto.addOns        if (addOnsToToggle.isNullOrEmpty()) throw IllegalArgumentException("At least one add-on must be selected.")        val toggledAddOns = mutableSetOf<AddOn>()        addOnsToToggle.forEach { dto ->            val foodAddOn = food.foodAddOns.find { it.addOn.id == dto.itemId }                ?: throw RequestedEntityNotFoundException("Food add-on with id ${dto.itemId} not found.")            if (foodAddOn.addOn.availability != Availability.fromString(requireNotNull(dto.availability))) {                foodAddOn.addOn.availability = Availability.fromString(requireNotNull(dto.availability))                toggledAddOns.add(foodAddOn.addOn)            }        }        addOnRepository.saveAllAndFlush(toggledAddOns)    }    private fun changeComplementAvailability(foodAvailabilityDto: FoodAvailabilityDto, food: Food) {        val incomingComplements = foodAvailabilityDto.complements        if (incomingComplements.isNullOrEmpty()) throw IllegalArgumentException("At least one complement must be selected.")        val updatedComplements = mutableSetOf<Complement>()        incomingComplements.forEach { dto ->            val foodComplement = food.foodComplements.find { it.complement.id == dto.itemId }                ?: throw RequestedEntityNotFoundException("Food complement with id ${dto.itemId} not found.")            if (foodComplement.complement.availability != Availability.fromString(requireNotNull(dto.availability))) {                foodComplement.complement.availability = Availability.fromString(requireNotNull(dto.availability))                updatedComplements.add(foodComplement.complement)            }        }        complementRepository.saveAllAndFlush(updatedComplements)    }    private fun changeFoodSizeAvailability(foodAvailabilityDto: FoodAvailabilityDto, food: Food) {        val incomingFoodSizes = foodAvailabilityDto.foodSizes        if (incomingFoodSizes.isNullOrEmpty()) throw IllegalArgumentException("Please select at least one food size.")        val foodSizes = food.foodSizes.associateBy { it.id }        incomingFoodSizes.forEach { dto ->            val sizeId = dto.sizeId ?: throw IllegalArgumentException("Size ID cannot be null.")            val foodSize = foodSizes[dto.sizeId] ?: throw IllegalArgumentException("Size with $sizeId cannot be found.")            if (foodSize.availability != Availability.fromString(dto.availability)) {                foodSize.availability = Availability.fromString(dto.availability)            }        }    }}